import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface SourceData {
  name: string;
  users: number;
}

interface WidgetData {
  sources: SourceData[];
}

interface MetaData {
  theme: string;
  primaryColor: string;
}

export default function Widget() {
  const widgetData = response.data as WidgetData;
  const metaData = response.meta as MetaData;

  const totalUsers = widgetData.sources.reduce((sum, source) => sum + source.users, 0);

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 280,
        maxWidth: 380,
        bgcolor: metaData.theme === 'dark' ? '#424242' : '#FFFFFF',
      }}
      elevation={2}
    >
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Typography variant="h6" color="primary" sx={{ mb: 1 }}>
            Traffic Sources
          </Typography>
          <Stack direction="row" spacing={0.5}>
            {widgetData.sources.map((source) => (
              <Chip
                key={source.name}
                label={`${source.name}: ${source.users}`}
                sx={{ fontSize: '11px', px: 1, py: 0.5, bgcolor: metaData.primaryColor, color: '#FFF' }}
              />
            ))}
          </Stack>
          <PieChart
            height={120}
            series={[
              {
                data: widgetData.sources.map((source) => ({
                  label: source.name,
                  value: source.users,
                })),
                label: { show: true, position: 'outside', formatter: '{b}: {d}%' },
                color: [metaData.primaryColor, metaData.accentColor, '#FFAB00'],
              },
            ]}
            margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            sx={{
              '& .MuiPieSegment-label': {
                fontSize: 10,
                fill: '#FFF',
              },
            }}
          />
          <Box>
            <Typography variant="body2" color="text.secondary">
              Total Users: {totalUsers}
            </Typography>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
